using System.ComponentModel;
using System.Text.Json;
using Microsoft.Extensions.Logging;
using ModelContextProtocol.Server;

[McpServerToolType]
public class ApiTools(HttpClient httpClient, ILogger<ApiTools> logger)
{
    [McpServerTool, Description("Fetches data from an external API endpoint via HTTP GET.")]
    public async Task<string> FetchFromApi(
        [Description("Full URL of the API endpoint to call")] string url,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching data from {Url}", url);

        var response = await httpClient.GetAsync(url, cancellationToken);
        response.EnsureSuccessStatusCode();

        var content = await response.Content.ReadAsStringAsync(cancellationToken);
        logger.LogInformation("Received {Length} characters", content.Length);

        // Try to pretty-print JSON; return raw text otherwise
        try
        {
            var doc = JsonDocument.Parse(content);
            return JsonSerializer.Serialize(doc, new JsonSerializerOptions { WriteIndented = true });
        }
        catch (JsonException)
        {
            return content;
        }
    }
}

using System.ComponentModel;
using Microsoft.Extensions.AI;
using ModelContextProtocol.Server;

[McpServerPromptType]
public static class SummarizationPrompts
{
    [McpServerPrompt, Description("Summarize content into a concise paragraph.")]
    public static ChatMessage Summarize(
        [Description("The text content to summarize")] string content) =>
        new(ChatRole.User, $"Summarize the following content into a concise paragraph:\n\n{content}");

    [McpServerPrompt, Description("Summarize content as a bullet-point list of key takeaways.")]
    public static ChatMessage SummarizeAsBullets(
        [Description("The text content to summarize")] string content) =>
        new(ChatRole.User, $"Extract the key takeaways from the following content as a bullet-point list:\n\n{content}");
}

